    /**
     * Discover a device on the local network by IP
     */
    public void discoverDevice(String ipAddress, ApiCallback<DeviceInfo> callback) {
        if (!isLocalAddress(ipAddress)) {
            callback.onError(new IllegalArgumentException("Not a local network address: " + ipAddress));
            return;
        }

        // Try HTTPS first, fall back to HTTP for legacy devices
        String httpsUrl = "https://" + ipAddress + "/api/info";
        String httpUrl = "http://" + ipAddress + "/api/info";

        Request httpsRequest = new Request.Builder()
                .url(httpsUrl)
                .get()
                .addHeader("Accept", "application/json")
                .build();

        localClient.newCall(httpsRequest).enqueue(new Callback() {
            @Override
            public void onFailure(Call call, IOException e) {
                Log.d(TAG, "HTTPS discovery failed for " + ipAddress + ", trying HTTP: " + e.getMessage());
                // Fallback to HTTP
                Request httpRequest = new Request.Builder()
                        .url(httpUrl)
                        .get()
                        .addHeader("Accept", "application/json")
                        .build();
                executeAsync(localClient, httpRequest, DeviceInfo.class, new ApiCallback<DeviceInfo>() {
                    @Override
                    public void onSuccess(DeviceInfo result) {
                        result.setLocalIp(ipAddress);
                        result.setUsesHttps(false);
                        discoveredDevices.put(ipAddress, result);
                        callback.onSuccess(result);
                    }

                    @Override
                    public void onError(Throwable error) {
                        callback.onError(error);
                    }
                });
            }

            @Override
            public void onResponse(Call call, Response response) throws IOException {
                try {
                    if (response.isSuccessful() && response.body() != null) {
                        String body = response.body().string();
                        DeviceInfo info = gson.fromJson(body, DeviceInfo.class);
                        info.setLocalIp(ipAddress);
                        info.setUsesHttps(true);
                        discoveredDevices.put(ipAddress, info);
                        callback.onSuccess(info);
                    } else {
                        callback.onError(new IOException("Discovery failed: " + response.code()));
                    }
                } finally {
                    response.close();
                }
            }
        });
    }

    /**
     * Scan a range of local IPs for devices
     */
    public void scanLocalNetwork(String subnet, int startHost, int endHost, DeviceScanCallback callback) {
        new Thread(() -> {
            int found = 0;
            for (int i = startHost; i <= endHost; i++) {
                String ip = subnet + "." + i;
                try {
                    InetAddress address = InetAddress.getByName(ip);
                    if (address.isReachable(200)) {
                        discoverDevice(ip, new ApiCallback<DeviceInfo>() {
                            @Override
                            public void onSuccess(DeviceInfo result) {
                                callback.onDeviceFound(result);
                            }

                            @Override
                            public void onError(Throwable error) {
                                // Not an IoT device, ignore
                                Log.v(TAG, "Host " + ip + " is not an IoT device");
                            }
                        });
                        found++;
                    }
                } catch (IOException e) {
                    // Host not reachable, continue
                }
                callback.onScanProgress(i - startHost + 1, endHost - startHost + 1);
            }
            callback.onScanComplete(found);
        }).start();
    }

    /**
     * Send a command directly to a local device
     */
    public void sendLocalCommand(String ipAddress, DeviceCommand command, ApiCallback<CommandResponse> callback) {
        if (!isLocalAddress(ipAddress)) {
            callback.onError(new IllegalArgumentException("Not a local network address: " + ipAddress));
            return;
        }

        DeviceInfo cached = discoveredDevices.get(ipAddress);
        String protocol = (cached != null && !cached.isUsesHttps()) ? "http" : "https";
        String url = protocol + "://" + ipAddress + "/api/command";
        String json = gson.toJson(command);

        Request request = new Request.Builder()
                .url(url)
                .post(RequestBody.create(json, JSON))
                .addHeader("Accept", "application/json")
                .build();

        executeAsync(localClient, request, CommandResponse.class, callback);
    }

