    /**
     * Update firmware on local device directly
     */
    public void updateLocalFirmware(String ipAddress, byte[] firmwareData, String version,
                                     FirmwareUpdateCallback callback) {
        if (!isLocalAddress(ipAddress)) {
            callback.onError(new Throwable("Not a local network address: " + ipAddress));
            return;
        }

        DeviceInfo cached = discoveredDevices.get(ipAddress);
        String protocol = (cached != null && !cached.isUsesHttps()) ? "http" : "https";
        String url = protocol + "://" + ipAddress + "/api/firmware/update";

        RequestBody body = new okhttp3.MultipartBody.Builder()
                .setType(okhttp3.MultipartBody.FORM)
                .addFormDataPart("version", version)
                .addFormDataPart("firmware", "firmware.bin",
                        RequestBody.create(firmwareData, MediaType.parse("application/octet-stream")))
                .build();

        Request request = new Request.Builder()
                .url(url)
                .post(body)
                .addHeader("Accept", "application/json")
                .build();

        // Use a client with extended timeouts for firmware updates
        OkHttpClient firmwareClient = localClient.newBuilder()
                .readTimeout(120, TimeUnit.SECONDS)
                .writeTimeout(120, TimeUnit.SECONDS)
                .build();

        callback.onProgress(0);

        firmwareClient.newCall(request).enqueue(new Callback() {
            @Override
            public void onFailure(Call call, IOException e) {
                callback.onError(e);
            }

            @Override
            public void onResponse(Call call, Response response) throws IOException {
                try {
                    if (response.isSuccessful()) {
                        callback.onProgress(100);
                        callback.onComplete();
                    } else {
                        callback.onError(new IOException("Firmware update failed: " + response.code()));
                    }
                } finally {
                    response.close();
                }
            }
        });
    }

