    // ==================== Internal Methods ====================

    private <T> void executeAsync(OkHttpClient client, Request request, Class<T> responseType,
                                   ApiCallback<T> callback) {
        client.newCall(request).enqueue(new Callback() {
            @Override
            public void onFailure(Call call, IOException e) {
                Log.e(TAG, "Request failed: " + request.url(), e);
                callback.onError(e);
            }

            @Override
            public void onResponse(Call call, Response response) throws IOException {
                try {
                    if (response.isSuccessful()) {
                        ResponseBody body = response.body();
                        if (body != null) {
                            String responseStr = body.string();
                            Log.d(TAG, "Response: " + responseStr);
                            T result = gson.fromJson(responseStr, responseType);
                            callback.onSuccess(result);
                        } else {
                            callback.onError(new IOException("Empty response body"));
                        }
                    } else {
                        String errorBody = response.body() != null ? response.body().string() : "No error body";
                        ApiException exception = new ApiException(
                                response.code(),
                                response.message(),
                                errorBody
                        );
                        Log.e(TAG, "API error: " + response.code() + " " + errorBody);
                        callback.onError(exception);
                    }
                } finally {
                    response.close();
                }
            }
        });
    }

    private <T> T executeSync(OkHttpClient client, Request request, Class<T> responseType) throws IOException {
        try (Response response = client.newCall(request).execute()) {
            if (response.isSuccessful() && response.body() != null) {
                String responseStr = response.body().string();
                return gson.fromJson(responseStr, responseType);
            } else {
                String errorBody = response.body() != null ? response.body().string() : "No error body";
                throw new ApiException(response.code(), response.message(), errorBody);
            }
        }
    }

    private OkHttpClient createLocalClient(HttpLoggingInterceptor loggingInterceptor) {
        try {
            // Trust all certificates for local network devices (self-signed certs)
            final TrustManager[] trustAllCerts = new TrustManager[]{
                    new X509TrustManager() {
                        @Override
                        public void checkClientTrusted(X509Certificate[] chain, String authType) {
                        }

                        @Override
                        public void checkServerTrusted(X509Certificate[] chain, String authType) {
                        }

                        @Override
                        public X509Certificate[] getAcceptedIssuers() {
                            return new X509Certificate[]{};
                        }
                    }
            };

            final SSLContext sslContext = SSLContext.getInstance("TLS");
            sslContext.init(null, trustAllCerts, new SecureRandom());
            final SSLSocketFactory sslSocketFactory = sslContext.getSocketFactory();

            return new OkHttpClient.Builder()
                    .connectTimeout(LOCAL_CONNECT_TIMEOUT, TimeUnit.SECONDS)
                    .readTimeout(LOCAL_READ_TIMEOUT, TimeUnit.SECONDS)
                    .writeTimeout(LOCAL_WRITE_TIMEOUT, TimeUnit.SECONDS)
                    .sslSocketFactory(sslSocketFactory, (X509TrustManager) trustAllCerts[0])
                    .hostnameVerifier((hostname, session) -> isLocalAddress(hostname))
                    .addInterceptor(loggingInterceptor)
                    .retryOnConnectionFailure(true)
                    .build();
        } catch (NoSuchAlgorithmException | KeyManagementException e) {
            Log.e(TAG, "Failed to create local client with custom SSL", e);
            // Fallback to a basic client
            return new OkHttpClient.Builder()
                    .connectTimeout(LOCAL_CONNECT_TIMEOUT, TimeUnit.SECONDS)
                    .readTimeout(LOCAL_READ_TIMEOUT, TimeUnit.SECONDS)
                    .writeTimeout(LOCAL_WRITE_TIMEOUT, TimeUnit.SECONDS)
                    .addInterceptor(loggingInterceptor)
                    .retryOnConnectionFailure(true)
                    .build();
        }
    }

    private boolean isLocalAddress(String address) {
        return address.startsWith("192.168.") ||
                address.startsWith("10.") ||
                address.startsWith("172.16.") ||
                address.startsWith("172.17.") ||
                address.startsWith("172.18.") ||
                address.startsWith("172.19.") ||
                address.startsWith("172.20.") ||
                address.startsWith("172.21.") ||
                address.startsWith("172.22.") ||
                address.startsWith("172.23.") ||
                address.startsWith("172.24.") ||
                address.startsWith("172.25.") ||
                address.startsWith("172.26.") ||
                address.startsWith("172.27.") ||
                address.startsWith("172.28.") ||
                address.startsWith("172.29.") ||
                address.startsWith("172.30.") ||
                address.startsWith("172.31.");
    }

    public ConcurrentHashMap<String, DeviceInfo> getDiscoveredDevices() {
        return discoveredDevices;
    }

    public void clearDiscoveredDevices() {
        discoveredDevices.clear();
    }

    /**
     * Cancel all pending requests
     */
    public void cancelAllRequests() {
        cloudClient.dispatcher().cancelAll();
        localClient.dispatcher().cancelAll();
    }

    /**
     * Shutdown the client and release resources
     */
    public void shutdown() {
        cancelAllRequests();
        cloudClient.connectionPool().evictAll();
        localClient.connectionPool().evictAll();
        try {
            if (cloudClient.cache() != null) cloudClient.cache().close();
            if (localClient.cache() != null) localClient.cache().close();
        } catch (IOException e) {
            Log.e(TAG, "Error closing cache", e);
        }
    }

    // ==================== Auth Interceptor ====================

    private class AuthInterceptor implements Interceptor {
        @Override
        public Response intercept(Chain chain) throws IOException {
            Request original = chain.request();
            Request.Builder builder = original.newBuilder()
                    .header("Content-Type", "application/json")
                    .header("Accept", "application/json")
                    .header("User-Agent", "IoTManager-Android/1.0");

            if (authToken != null && !authToken.isEmpty()) {
                builder.header("Authorization", "Bearer " + authToken);
            }

            return chain.proceed(builder.build());
        }
    }

